-- =============================================
-- Email translations for N8N workflows
-- UTF-8 safe - stored in Supabase, read by N8N Code nodes
-- Řeší problém s diakritikou v N8N Code nodech
-- 06.03.2026
-- =============================================

CREATE TABLE IF NOT EXISTS email_translations (
  id serial PRIMARY KEY,
  template_key text NOT NULL,
  lang text NOT NULL,
  greeting text NOT NULL,
  body text NOT NULL,
  sign_off text NOT NULL,
  subject_tpl text,
  extra jsonb,
  UNIQUE(template_key, lang)
);

COMMENT ON TABLE email_translations IS 'Email překlady pro N8N WF1/WF3/WF6 — UTF-8';

-- =============================================
-- WF1: Bug report acknowledgment emails
-- =============================================
ON CONFLICT (template_key, lang) DO UPDATE SET greeting=EXCLUDED.greeting, body=EXCLUDED.body, sign_off=EXCLUDED.sign_off;

-- =============================================
-- WF3: GDPR deletion confirmation emails
-- =============================================
ON CONFLICT (template_key, lang) DO UPDATE SET greeting=EXCLUDED.greeting, body=EXCLUDED.body, sign_off=EXCLUDED.sign_off, subject_tpl=EXCLUDED.subject_tpl, extra=EXCLUDED.extra;

-- =============================================
-- WF6: Business/spam response emails
-- =============================================
ON CONFLICT (template_key, lang) DO UPDATE SET greeting=EXCLUDED.greeting, body=EXCLUDED.body, sign_off=EXCLUDED.sign_off, subject_tpl=EXCLUDED.subject_tpl;

-- Grant read access to service role (for N8N)
GRANT SELECT ON email_translations TO service_role;
GRANT SELECT ON email_translations TO anon;
